mapper.select:
SELECT ev_info.id, ev_info.league_id, ev_info.league_name, ev_info.events_id, ev_info.events_code, ev_info.team_name, ev_info.sport_name, ev_info.sport_type, s_info.created_time as updated_time, ev_info.start_time as start_time, ev_info.end_time as end_time, s_info.creator as updater , CASE WHEN s_info.id IS NULL THEN 0 ELSE 1 END AS pinStatus, s_info.created_time AS sortTime from sport_events_recommend ev_info LEFT JOIN site_sport_events_recommend s_info ON ev_info.id = s_info.sport_recommend_id AND s_info.site_code = #{siteCode}
where ev_info.end_time >= #{vo.endTime}
AND ev_info.sport_type = #{vo.sportType}
AND ev_info.league_name LIKE CONCAT('%', #{vo.leagueName}, '%')
AND ev_info.events_id = #{vo.eventsId}
AND ev_info.team_name LIKE CONCAT('%', #{vo.teamName}, '%')
AND ev_info.start_time >= #{vo.endTime}
AND ev_info.start_time <= #{vo.endTime}
ORDER BY CASE WHEN s_info.id IS NULL THEN 1 ELSE 0 END, -- 非空排前，空排后 CASE WHEN s_info.id IS NULL THEN ev_info.start_time ELSE s_info.created_time END ASC
